// Scan every workflow definition for anything that looks like a secret
// or a real email address.
// Patterns are built by concatenation so this scanner never flags itself.
const PATTERNS = [
  ['openai_style_key', 'sk' + '-[A-Za-z0-9_-]{10,}'],
  ['slack_bot_token', 'xox' + 'b-[A-Za-z0-9-]{10,}'],
  ['github_token', 'gh' + 'p_[A-Za-z0-9]{20,}'],
  ['github_fine_grained_pat', 'github' + '_pat_[A-Za-z0-9_]{20,}'],
  ['aws_access_key_id', 'AKIA' + '[0-9A-Z]{16}'],
  ['bearer_header_literal', 'Bearer ' + '[A-Za-z0-9._~+/=-]{15,}'],
  ['real_email_address', '[A-Za-z0-9._%+-]+@(?!example\\.com|example\\.org|example\\.net)[A-Za-z0-9-]+(\\.[A-Za-z0-9-]+)*\\.[A-Za-z]{2,}'],
];

function mask(value) {
  const s = String(value);
  return s.length <= 6 ? s[0] + '***' : s.slice(0, 4) + '***' + s.slice(-2);
}

const results = [];
for (const item of $input.all()) {
  const wf = item.json || {};
  const workflowName = String(wf.name || 'unnamed workflow');
  let text = '';
  try {
    text = JSON.stringify(wf);
  } catch (e) {
    results.push({
      json: {
        workflow_name: workflowName,
        status: 'error',
        finding_count: 0,
        findings: [],
        note: 'Could not serialize this workflow - inspect it manually.',
      },
    });
    continue;
  }

  const findings = [];
  for (const [label, source] of PATTERNS) {
    const regex = new RegExp(source, 'g');
    let match;
    let count = 0;
    while ((match = regex.exec(text)) !== null && count < 20) {
      findings.push({ pattern: label, match_preview: mask(match[0]) });
      count++;
    }
  }

  results.push({
    json: {
      workflow_name: workflowName,
      status: findings.length === 0 ? 'pass' : 'fail',
      finding_count: findings.length,
      findings,
      note:
        findings.length === 0
          ? 'Clean.'
          : 'DO NOT EXPORT OR SHARE. Move the value into an n8n credential, then re-run.',
    },
  });
}
return results;
